(window.webpackJsonp=window.webpackJsonp||[]).push([[152],{675:function(n,e,a){"use strict";a.r(e);var p=a(29),g=Object(p.a)({},(function(){var n=this,e=n.$createElement,a=n._self._c||e;return a("ContentSlotsDistributor",{attrs:{"slot-key":n.$parent.slotKey}},[a("h1",{attrs:{id:"dpkg用法详解"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#dpkg用法详解"}},[n._v("#")]),n._v(" "),a("a",{attrs:{href:"https://www.cnblogs.com/li-mei/p/5832099.html",target:"_blank",rel:"noopener noreferrer"}},[n._v("dpkg用法详解"),a("OutboundLink")],1)]),n._v(" "),a("p",[n._v("原文出处[博客园]：https://www.cnblogs.com/li-mei/p/5832099.html")]),n._v(" "),a("p",[n._v("dpkg是一个Debian的一个命令行工具，它可以用来安装、删除、构建和管理Debian的软件包。\n下面是它的一些命令解释：\n1）安装软件\n命令行：dpkg -i <.deb file name>\n示例：dpkg -i avg71flm_r28-1_i386.deb\n2）安装一个目录下面所有的软件包\n命令行：dpkg -R\n示例：dpkg -R /usr/local/src\n3）释放软件包，但是不进行配置\n命令行：dpkg –unpack package_file 如果和-R一起使用，参数可以是一个目录\n示例：dpkg –unpack avg71flm_r28-1_i386.deb\n4）重新配置和释放软件包\n命令行：dpkg –configure package_file\n如果和-a一起使用，将配置所有没有配置的软件包\n示例：dpkg –configure avg71flm_r28-1_i386.deb\n5）删除软件包（保留其配置信息）\n命令行：dpkg -r\n示例：dpkg -r avg71flm\n6）替代软件包的信息\n命令行：dpkg –update-avail "),a("Packages-file",[n._v("\n7）合并软件包信息\ndpkg –merge-avail "),a("Packages-file",[n._v("\n8）从软件包里面读取软件的信息\n命令行：dpkg -A package_file\n9）删除一个包（包括配置信息）\n命令行：dpkg -P\n10）丢失所有的Uninstall的软件包信息\n命令行：dpkg –forget-old-unavail\n11）删除软件包的Avaliable信息\n命令行：dpkg –clear-avail\n12）查找只有部分安装的软件包信息\n命令行：dpkg -C\n13）比较同一个包的不同版本之间的差别\n命令行：dpkg –compare-versions ver1 op ver2\n14）显示帮助信息\n命令行：dpkg –help\n15）显示dpkg的Licence\n命令行：dpkg –licence (or) dpkg –license\n16）显示dpkg的版本号\n命令行：dpkg –version\n17）建立一个deb文件\n命令行：dpkg -b direc×y [filename]\n18）显示一个Deb文件的目录\n命令行：dpkg -c filename\n19）显示一个Deb的说明\n命令行：dpkg -I filename [control-file]\n20）搜索Deb包\n命令行：dpkg -l package-name-pattern\n示例：dpkg -I vim\n21)显示所有已经安装的Deb包，同时显示版本号以及简短说明\n命令行：dpkg -l\n22）报告指定包的状态信息\n命令行：dpkg -s package-name\n示例：dpkg -s ssh\n23）显示一个包安装到系统里面的文件目录信息\n命令行：dpkg -L package-Name\n示例：dpkg -L apache2\n24）搜索指定包里面的文件（模糊查询）\n命令行：dpkg -S filename-search-pattern\n25）显示包的具体信息\n命令行：dpkg -p package-name\n示例：dpkg -p cacti")])],1)],1),n._v(" "),a("p",[n._v("最后：\n1、很多人抱怨用了Ubuntu或者Debian以后，不知道自己的软件给安装到什么地方了。其实可以用上面的dpkg -L命令来方便的查找。看来基础还是非常重要的，图形界面并不能够包办一切。\n2、有的时候，用“新力得”下载完成以后，没有配置，系统会提示用“dpkg –configure -all”来配置，具体为什么也可以从上面看到。\n3、现在Edgy里面可以看到Deb的信息。不过是在没有安装的时候（当然也可以重新打开那个包），可以看到Deb的文件路径。\n4、如果想暂时删除程序以后再安装，第5项还是比较实用的，毕竟在Linux下面配置一个软件也并非容易。")])])}),[],!1,null,null,null);e.default=g.exports}}]);